logging_pattern.test_template:

test('test name', async ({ page, ...fixtures }) => {
  const logger = getLogger()
  const source = 'test:{category}'  // e.g., 'test:signin', 'test:marketplace'

  logger.info(source, 'Starting test: {test name}')

  await test.step('Step description', async () => {
    logger.info(source, 'Executing: {step description}')
    // test code
  })

  // Log important data context
  logger.info(source, 'Created case', { caseId: 'abc123' })

  // Log on completion
  logger.info(source, 'Test completed successfully')
})

implementation_example.before_code:

import { test, expect } from '@playwright/test'
import { SigninPage } from '../../page-objects/SigninPage'

test.describe('Sign In', () => {
  test('should sign in with valid credentials', async ({ page }) => {
    const signinPage = new SigninPage(page)

    await signinPage.goto()
    await signinPage.login('user@example.com', 'password123')

    await expect(page).toHaveURL(/\/dashboard/)
  })
})

implementation_example.after_code:

import { test, expect } from '@playwright/test'
import { SigninPage } from '../../page-objects/SigninPage'
import { getLogger } from '../../utils/test-logger'

test.describe('Sign In', () => {
  test('should sign in with valid credentials', async ({ page }) => {
    const logger = getLogger()
    const source = 'test:signin'

    logger.info(source, 'Starting sign in test')

    const signinPage = new SigninPage(page)

    await test.step('Navigate to signin page', async () => {
      logger.info(source, 'Navigating to signin page')
      await signinPage.goto()
    })

    await test.step('Enter credentials and submit', async () => {
      logger.info(source, 'Entering credentials', { email: 'user@example.com' })
      await signinPage.login('user@example.com', 'password123')
    })

    await test.step('Verify redirect to dashboard', async () => {
      logger.info(source, 'Verifying dashboard redirect')
      await expect(page).toHaveURL(/\/dashboard/)
      logger.info(source, 'Sign in completed successfully')
    })
  })
})

minimal_logging_example.code:

import { test, expect } from '@playwright/test'
import { getLogger } from '../../utils/test-logger'

test('should display case details', async ({ page }) => {
  const logger = getLogger()
  const source = 'test:case'

  logger.info(source, 'Test: display case details')

  // Test code here...
  const caseId = await page.locator('[data-testid="case-id"]').textContent()
  logger.info(source, 'Viewing case', { caseId })

  // Assertions...

  logger.info(source, 'Test completed')
})
